const BASE='https://atlas.gls-spain.es';
const GLS_USER=$env.GLS_USER||'';
const GLS_PASS=$env.GLS_PASS||'';
function gc(h){return typeof h.getSetCookie==='function'?h.getSetCookie():(h.get('set-cookie')?[h.get('set-cookie')]:[]);}
function pc(raw,ex={}){const m={...ex};const hs=Array.isArray(raw)?raw:raw?[String(raw)]:[];for(const h of hs){const p=h.split(';')[0].trim();const eq=p.indexOf('=');if(eq>0)m[p.substring(0,eq).trim()]=p;}return m;}
const cs=m=>Object.values(m).join('; ');
function csrf(html){const m=html.match(/name="__RequestVerificationToken"[^>]*value="([^"]+)"/);if(!m)throw new Error('CSRF no encontrado');return m[1];}

const r1=await fetch(`${BASE}/Account/Login`,{headers:{Accept:'text/html','User-Agent':'Mozilla/5.0'}});
const b1=await r1.text();
let ck=pc(gc(r1.headers));
const c1=csrf(b1);

const r2=await fetch(`${BASE}/Account/Login`,{method:'POST',redirect:'follow',headers:{Cookie:cs(ck),'Content-Type':'application/x-www-form-urlencoded',Referer:`${BASE}/Account/Login`,Accept:'text/html','User-Agent':'Mozilla/5.0'},body:new URLSearchParams({Username:GLS_USER,Password:GLS_PASS,__RequestVerificationToken:c1}).toString()});
const b2=await r2.text();
ck=pc(gc(r2.headers),ck);
if(b2.toLowerCase().includes('name="password"'))throw new Error('Login fallido — credenciales incorrectas. Revisa GLS_USER y GLS_PASS.');

const r3=await fetch(`${BASE}/delivery/index`,{headers:{Cookie:cs(ck),Accept:'text/html','User-Agent':'Mozilla/5.0'}});
const b3=await r3.text();
ck=pc(gc(r3.headers),ck);
if(b3.toLowerCase().includes('<title>sign in'))throw new Error('delivery/index devuelve login — sesión no autenticada');
const c2=csrf(b3);

const hoy=new Date();
const fmt=d=>`${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;

const r4=await fetch(`${BASE}/delivery/GetSummarySheets`,{method:'POST',headers:{Cookie:cs(ck),'Content-Type':'application/json','__RequestVerificationToken':c2,'X-Requested-With':'XMLHttpRequest',Accept:'application/json, text/javascript, */*; q=0.01',Referer:`${BASE}/delivery/index`,'User-Agent':'Mozilla/5.0'},body:JSON.stringify({filters:{since:fmt(new Date(hoy.getFullYear(),hoy.getMonth(),1)),until:fmt(hoy)}})});
const _s4=r4.status;
let raw=await r4.text();
if(typeof raw==='string'){try{raw=JSON.parse(raw);}catch(e){}}

const arr=raw?.data||raw?.sheets||raw?.hojas||raw?.repartidores||(Array.isArray(raw)?raw:[]);
const repartidores=arr.map(s=>({nombre:s.nombre||s.name||s.Name||s.driverName||s.Conductor||'Sin nombre',sheetCode:String(s.sheetCode||s.SheetCode||s.id||s.Id||''),placeCode:String(s.placeCode||s.PlaceCode||s.cp||s.postalCode||'')}));

return [{json:{repartidores,_status:_s4,_raw:raw}}];

